   481→    <script>
   482→        /* Sidebar active state on scroll */
   483→        (function () {
   484→            const sections = document.querySelectorAll('h1[id], h2[id], h3[id]');
   485→            const links = document.querySelectorAll('.sidebar a');
   486→
   487→            window.addEventListener('scroll', function () {
   488→                let current = '';
   489→                sections.forEach(function (section) {
   490→                    if (window.scrollY >= section.offsetTop - 80) {
   491→                        current = section.getAttribute('id');
   492→                    }
   493→                });
   494→                links.forEach(function (link) {
   495→                    link.classList.remove('active');
   496→                    if (link.getAttribute('href') === '#' + current) {
   497→                        link.classList.add('active');
   498→                    }
   499→                });
   500→            });
